const body = $input.first().json.body || $input.first().json;
const action = body.action || '';
const namespace = body.namespace || 'default';
const name = body.name || '';
const replicas = body.replicas || 1;
const allowed_actions = ['pod-status', 'deployment-status', 'restart', 'scale', 'namespace-summary'];
if (!allowed_actions.includes(action)) {
  return [{ json: { error: true, message: `Unknown action '${action}'. Allowed: ${allowed_actions.join(', ')}`, status: 400 }}];
}
return [{ json: { action, namespace, name, replicas } }];

const { action, namespace, name, replicas } = $json;
const base = $env.K8S_API_HOST;
let url = '', method = 'GET', body = null;
switch (action) {
  case 'pod-status':
    url = name ? `${base}/api/v1/namespaces/${namespace}/pods/${name}` : `${base}/api/v1/namespaces/${namespace}/pods`;
    break;
  case 'deployment-status':
    url = name ? `${base}/apis/apps/v1/namespaces/${namespace}/deployments/${name}` : `${base}/apis/apps/v1/namespaces/${namespace}/deployments`;
    break;
  case 'restart':
    url = `${base}/apis/apps/v1/namespaces/${namespace}/deployments/${name}`;
    method = 'PATCH';
    body = JSON.stringify({ spec: { template: { metadata: { annotations: { 'kubectl.kubernetes.io/restartedAt': new Date().toISOString() } } } } });
    break;
  case 'scale':
    url = `${base}/apis/apps/v1/namespaces/${namespace}/deployments/${name}/scale`;
    method = 'PATCH';
    body = JSON.stringify({ spec: { replicas: parseInt(replicas) } });
    break;
  case 'namespace-summary':
    url = `${base}/api/v1/namespaces/${namespace}/pods`;
    break;
}
return [{ json: { url, method, body, action, namespace, name, replicas } }];

const action = $('Build K8s Request').first().json.action;
const namespace = $('Build K8s Request').first().json.namespace;
const name = $('Build K8s Request').first().json.name;
const data = $input.first().json;
let result = {};
switch (action) {
  case 'pod-status':
    result = data.items
      ? { action, namespace, pods: data.items.map(p => ({ name: p.metadata.name, phase: p.status.phase, restarts: (p.status.containerStatuses||[]).reduce((s,c)=>s+c.restartCount,0), node: p.spec.nodeName })) }
      : { action, namespace, name, phase: data.status?.phase, restarts: (data.status?.containerStatuses||[]).reduce((s,c)=>s+c.restartCount,0) };
    break;
  case 'deployment-status':
    result = data.items
      ? { action, namespace, deployments: data.items.map(d => ({ name: d.metadata.name, ready: `${d.status.readyReplicas||0}/${d.spec.replicas}`, image: d.spec.template.spec.containers[0]?.image })) }
      : { action, namespace, name, ready: `${data.status?.readyReplicas||0}/${data.spec?.replicas}`, image: data.spec?.template?.spec?.containers[0]?.image };
    break;
  case 'restart':
    result = { action, namespace, name, status: 'restart_triggered', timestamp: new Date().toISOString() };
    break;
  case 'scale':
    result = { action, namespace, name, replicas: $('Build K8s Request').first().json.replicas, status: 'scale_triggered' };
    break;
  default:
    result = { action, namespace, data: data.items?.length || 'ok' };
}
return [{ json: result }];
